changeSet.sql:
ALTER TABLE project_file ADD COLUMN IF NOT EXISTS code_language TEXT;
ALTER TABLE course ADD COLUMN IF NOT EXISTS code_language TEXT;

UPDATE project_file pf
SET code_language = cl.slug
FROM code_languages cl
WHERE pf.code_language IS NULL
  AND pf.code_language_id = cl.id;

UPDATE course c
SET code_language = cl.slug
FROM code_languages cl
WHERE c.code_language IS NULL
  AND c.code_language_id = cl.id;

ALTER TABLE project_file DROP CONSTRAINT IF EXISTS fk_project_file_code_language;
ALTER TABLE user_project DROP CONSTRAINT IF EXISTS fk_user_project_code_language;
ALTER TABLE course DROP CONSTRAINT IF EXISTS fk_course_code_language;

ALTER TABLE project_file DROP COLUMN IF EXISTS code_language_id;
ALTER TABLE user_project DROP COLUMN IF EXISTS code_language_id;
ALTER TABLE course DROP COLUMN IF EXISTS code_language_id;
